<template><AdminTablePage title="轮播图管理" desc="维护门户首页轮播宣传图" :list="list" :total="list.length" :loading="loading" :query="query" @load="load" @open="open"><template #columns><el-table-column label="预览" width="140"><template #default="{row}"><el-image :src="row.imageUrl" style="width:100px;height:52px;border-radius:4px" fit="cover"/></template></el-table-column><el-table-column prop="title" label="标题"/><el-table-column prop="linkUrl" label="链接" show-overflow-tooltip/><el-table-column prop="sort" label="排序" width="80"/><el-table-column label="状态" width="90"><template #default="{row}"><el-tag :type="row.status===1?'success':'info'">{{row.status===1?'显示':'隐藏'}}</el-tag></template></el-table-column></template><template #rowActions="{row}"><el-button text type="primary" @click="open(row)">编辑</el-button><el-button text type="danger" @click="del(row)">删除</el-button></template><template #dialogs><el-dialog v-model="dialog" title="轮播图" width="560px"><el-form :model="form" label-width="80px"><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="图片URL"><el-input v-model="form.imageUrl"/></el-form-item><el-form-item label="链接"><el-input v-model="form.linkUrl"/></el-form-item><el-form-item label="排序"><el-input-number v-model="form.sort" :min="0"/></el-form-item><el-form-item label="显示"><el-switch v-model="form.status" :active-value="1" :inactive-value="0"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></template></AdminTablePage></template><script setup>import{reactive,ref,onMounted}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import AdminTablePage from '@/components/AdminTablePage.vue';import{adminApi}from'@/api';const query=reactive({pageNum:1,pageSize:999});const list=ref([]),loading=ref(false),dialog=ref(false);const form=reactive({});const load=async()=>{loading.value=true;try{list.value=(await adminApi.banners()).data||[]}finally{loading.value=false}};const open=row=>{Object.keys(form).forEach(k=>delete form[k]);Object.assign(form,row||{status:1,sort:0});dialog.value=true};const save=async()=>{await adminApi.saveBanner(form);ElMessage.success('保存成功');dialog.value=false;load()};const del=row=>ElMessageBox.confirm('确定删除该轮播图？').then(async()=>{await adminApi.delBanner(row.id);load()});onMounted(load)</script>